import matplotlib.pyplot as plt
import numpy as np
from collections import defaultdict
import os
import json

# Create graphs directory if it doesn't exist
script_dir = os.path.dirname(os.path.abspath(__file__))
graphs_dir = os.path.join(script_dir, 'graphs')
os.makedirs(graphs_dir, exist_ok=True)

# Load data from accuracy_data.json (generated by run_mock_pipeline.py)
data_file = os.path.join(script_dir, 'accuracy_data.json')
if os.path.exists(data_file):
    with open(data_file, 'r') as f:
        benchmark_data = json.load(f)
    print(f"Loaded {len(benchmark_data)} entries from {data_file}")
else:
    print(f"Error: {data_file} not found. Run run_mock_pipeline.py first to generate benchmark data.")
    exit(1)

# Filter for parallel workers data (entries with max_workers field)
parallel_data = [d for d in benchmark_data if 'max_workers' in d or 'workers' in d]

if not parallel_data:
    print("No parallel workers data found in accuracy_data.json.")
    print("This data is only generated when running with --parallel-workers argument.")
    print("Skipping parallel time graphs.")
    exit(0)

# Organize data by dataset size and calculate mean + std for each worker count
def analyze_data(data, dataset_filter):
    """Filter data by dataset size and group by worker count."""
    filtered = [d for d in data if d['dataset'] == dataset_filter]
    
    worker_times = defaultdict(list)
    for entry in filtered:
        worker_times[entry['workers']].append(entry['total'])
    
    workers = sorted(worker_times.keys())
    means = [np.mean(worker_times[w]) for w in workers]
    stds = [np.std(worker_times[w]) for w in workers]
    
    return workers, means, stds

# Dataset configurations for individual graphs
# Note: These dataset names are used when running with --parallel-workers flag
# The 'dataset' field is set based on the date range in the mock data generation
datasets = [
    ('small', 'Parallel_Time_Small_Entries_1_entry', 'Small Entries (1 entry)', '2026-05-01 to 2026-05-02'),
    ('medium', 'Parallel_Time_Medium_Entries_9_entries', 'Medium Entries (9 entries)', '2026-05-01 to 2026-05-05'),
    ('large', 'Parallel_Time_Large_Entries_22_entries', 'Large Entries (22 entries)', '2026-05-01 to 2026-05-10')
]

# Check if we have any data to plot
has_data = False
for dataset_name, filename_prefix, title, date_range in datasets:
    workers, means, stds = analyze_data(parallel_data, dataset_name)
    
    if not workers:
        continue
    
    has_data = True
    fig, ax = plt.subplots(figsize=(8, 5))
    
    ax.errorbar(workers, means, yerr=stds, fmt='-o', capsize=5, 
                linewidth=2, markersize=8, ecolor='red', elinewidth=2)
    ax.set_xlabel('Number of Parallel Workers', fontsize=11)
    ax.set_ylabel('Processing Time (seconds)', fontsize=11)
    ax.set_title(f'{title}\n{date_range}\nqwen3-122B-A10B (no batching)', fontsize=10)
    ax.set_xticks(workers)
    ax.grid(True, alpha=0.3)
    ax.set_ylim(bottom=0)
    
    output_path = os.path.join(graphs_dir, f'{filename_prefix}.png')
    plt.savefig(output_path, dpi=150, bbox_inches='tight')
    print(f"Graph saved as '{output_path}'")
    plt.close()

if not has_data:
    print("No parallel workers data found for the specified dataset sizes.")
    print("Run with --parallel-workers to generate this data.")
else:
    print(f"\nAll graphs saved in '{graphs_dir}' directory.")